def _normalize_plate_rows(
    raw_plate_rows: dict[str, dict[str, object]]
) -> list[dict[str, object]]:
    """Flatten plate rows and expose standardized fields at top level."""
    by_category_counts: dict[str, int] = {}
    normalized_rows: list[dict[str, object]] = []

    for product_code, data in raw_plate_rows.items():
        if not isinstance(data, dict):
            continue
        row: dict[str, object] = {"product_code": str(product_code), **data}
        category = str(row.get("set", "")).strip()
        row["category"] = category
        by_category_counts[category] = by_category_counts.get(category, 0) + 1
        row["id"] = f"{by_category_counts[category]:02d}"
        row.setdefault("home", str(row.get("location", "")).strip())
        row.setdefault(
            "shorthand",
            SET_SHORTHAND_BY_CATEGORY.get(category, ""),
        )
        normalized_rows.append(row)

    return normalized_rows


PLATE_ROWS = _normalize_plate_rows(PLATES)

PLATES_BY_CODE = {row["product_code"]: row for row in PLATE_ROWS}


